import { Component } from '@angular/core';
import { finalize, Subscription } from 'rxjs';
import { FormControl, FormGroup, Validators,FormsModule } from '@angular/forms';
import { HttpService } from '../http.service';
import { ActivatedRoute, Router } from '@angular/router';
import { allContacts } from './contacts.interface';
import { Contact } from './add-contact/add-Contact.interface';

@Component({
  selector: 'app-contacts',
  templateUrl: './contacts.component.html',
  styleUrls: ['./contacts.component.scss']
})
export class ContactsComponent {
  data: allContacts[] = [];
  Form?: FormGroup;

  allcontacts?: Contact
  sub?: Subscription;



  buildForm(item?: allContacts) {
    this.Form = new FormGroup({
        firstName: new FormControl('',[
            Validators.required,
        ]),
        lastName: new FormControl('',[
            Validators.required,
        ]),
        email: new FormControl('',[
            Validators.required,
        ]),
        phone: new FormControl('',[
          Validators.required,
        ]),
        address: new FormControl('',[
        Validators.required,
    ]),
    });
}

getContact(id: string) {
  const sub = this.http.get<allContacts>(`contact/${id}`).subscribe(item => {
      this.allcontacts = item;
      this.buildForm(item);
      sub.unsubscribe();
  });
}



delete(item: allContacts) {
  if (!confirm('האם למחוק איש קשר?')) {
      return;
  }

  const sub = this.http.delete<void>(`contacts/${item.id}`).subscribe(() => {
      const i = this.data.findIndex(x => x.id === item.id);
      this.data.splice(i, 1);
      sub.unsubscribe();
  });
}


     constructor (private router: Router , private http: HttpService , private route: ActivatedRoute) {

      this.sub = this.route.params.subscribe(params => {
        if (params['id']) {
            this.getContact(params['id']);
        } else {
            this.buildForm();
        }
    });



     }

ngOnInit() {
  const sub= this.http.get<allContacts[]>('contacts').pipe(finalize(() => {
     if (sub.unsubscribe){
       sub.unsubscribe();
     }
      })).subscribe(data => {
          this.data=data
      })

     }

}
<p>contacts works!</p>

<h4>אנשי קשר</h4>
<button class="w3-btn w3-green w3-round w3-block" routerLink="/add-Contact"  >!!!איש קשר חדש<i class="fa far fa-plus-square"></i></button>

<table class="w3-table w3-striped w3-bordered">
    <thead>
        <tr>
            <th>שם פרטי</th>
            <th>שם משפחה</th>
            <th>טלפון</th>
            <th>אימייל</th>
            <th> כתובת </th>
        </tr>
    </thead>
    <tbody>
        <tr *ngFor="let item of data">
            <td>{{ item.firsName }}</td>
            <td>{{ item.lastName }}</td>
            <td>{{ item.phone }}</td>
            <td>{{ item.email }}</td>
            <td>{{ item.address }}</td>
            <td><button class="w3-btn w3-green w3-round"><i class="fa fa-edit" routerLink="/edit-Contact"></i>בלה</button></td>
            <td><button class="w3-btn w3-red w3-round" (click)="delete(item)">x</button></td>

        </tr>
    </tbody>
</table>
